import type { Identifier, RaRecord } from "ra-core";
import {
  CreateBase,
  Form,
  useGetIdentity,
  useListContext,
  useNotify,
  useRecordContext,
  useResourceContext,
  useUpdate,
} from "ra-core";
import { useFormContext, useFormState } from "react-hook-form";

import { SaveButton } from "@/components/ra-wrappers/form";
import { FormErrorSummary } from "@/components/ra-wrappers/FormErrorSummary";
import { createFormResolver } from "@/lib/zodErrorFormatting";
import { NoteInputs } from "./NoteInputs";
import { noteFormSchema, getCurrentDate } from "../validation/notes";

const foreignKeyMapping = {
  contacts: "contact_id",
  opportunities: "opportunity_id",
  organizations: "organization_id",
};

export const NoteCreate = ({
  reference,
}: {
  reference: "contacts" | "opportunities" | "organizations";
}) => {
  const resource = useResourceContext();
  // NoteCreate handles multiple parent types: Contact | Opportunity | Organization
  // Using RaRecord as the union type since we only need the id field
  const record = useRecordContext<RaRecord>();
  const { data: identity } = useGetIdentity();

  if (!record || !identity) return null;

  const formDefaults = {
    ...noteFormSchema.partial().parse({}),
    date: getCurrentDate(),
  };

  return (
    <CreateBase resource={resource} redirect={false}>
      <Form
        defaultValues={formDefaults}
        mode="onBlur"
        resolver={createFormResolver(noteFormSchema)}
      >
        <div className="space-y-3">
          <NoteFormContent reference={reference} record={record} />
        </div>
      </Form>
    </CreateBase>
  );
};

const NoteFormContent = ({
  reference,
  record,
}: {
  reference: "contacts" | "opportunities" | "organizations";
  record: RaRecord<Identifier>;
}) => {
  const { errors } = useFormState();

  return (
    <>
      <FormErrorSummary errors={errors} />
      <NoteInputs />
      <NoteCreateButton reference={reference} record={record} />
    </>
  );
};

const NoteCreateButton = ({
  reference,
  record,
}: {
  reference: "contacts" | "opportunities" | "organizations";
  record: RaRecord<Identifier>;
}) => {
  const [update] = useUpdate();
  const notify = useNotify();
  const { data: identity } = useGetIdentity();
  const { reset } = useFormContext();
  const { refetch } = useListContext();

  if (!record || !identity) return null;

  const handleSuccess = async () => {
    reset(noteFormSchema.partial().parse({}), { keepValues: false });

    // Only update last_seen for contacts (opportunities don't have last_seen)
    try {
      if (reference === "contacts") {
        await update(
          reference,
          {
            id: record.id,
            data: { last_seen: new Date().toISOString() },
            previousData: record,
          },
          { returnPromise: true }
        );
      }

      refetch();
      notify("Note added");
    } catch {
      notify("Note added, but failed to update contact last seen", { type: "warning" });
      refetch();
    }
  };

  return (
    <div className="flex justify-end">
      <SaveButton
        type="button"
        label="Add this note"
        transform={(data) => ({
          ...data,
          [foreignKeyMapping[reference]]: record.id,
          sales_id: identity.id,
          date: data.date || getCurrentDate(),
        })}
        mutationOptions={{
          onSuccess: handleSuccess,
        }}
      >
        Add this note
      </SaveButton>
    </div>
  );
};
